const AdminGalleries = () => {
  return (
    <section className="container mx-auto px-4 py-12">
      <h1 className="section-title">Manage Galleries</h1>
      <p className="section-subtitle">Upload gallery covers, edit descriptions, and publish new portfolios.</p>
      <div className="card p-8 mt-8">
        <p className="text-gray-600">Gallery management tools are available in the backend dashboard. Use this page to access the gallery workflow and maintain your portfolio content.</p>
      </div>
    </section>
  );
};

export default AdminGalleries;
